package com.baize.flux.connector.jdbc;
import com.baize.flux.api.sink.*; import com.baize.flux.api.table.*; import java.sql.*; import java.util.*;
final class JdbcSink implements Sink {private final Map<String,String> o; JdbcSink(Map<String,String> options){o=Map.copyOf(options);} public void validateInputSchema(TableSchema schema){var cols=o.get("columns");if(cols!=null&&cols.split(",").length!=schema.columns().size())throw new IllegalArgumentException("sink.columns must match source column count");} public SinkWriter createWriter(){return new Writer();} private String req(String key){var v=o.get(key);if(v==null||v.isBlank())throw new IllegalArgumentException("jdbc sink needs "+key);return v;} private final class Writer implements SinkWriter {Connection c; PreparedStatement s; public void open()throws SQLException{c=DriverManager.getConnection(req("url"),o.getOrDefault("username",""),o.getOrDefault("password",""));c.setAutoCommit(false);var cols=o.get("columns");if(cols==null)throw new IllegalArgumentException("jdbc sink needs columns");var names=cols.split(",");s=c.prepareStatement("INSERT INTO "+req("table")+" ("+cols+") VALUES ("+String.join(",",Collections.nCopies(names.length,"?"))+")");} public long write(RowBatch b)throws SQLException{for(var row:b.rows()){for(int i=0;i<row.values().size();i++)s.setObject(i+1,row.values().get(i));s.addBatch();}long n=0;for(int x:s.executeBatch())n+=Math.max(x,0);return n;} public void flush()throws SQLException{c.commit();} public void abort(Throwable ignored){try{if(c!=null)c.rollback();}catch(SQLException e){}} public void close()throws SQLException{if(s!=null)s.close();if(c!=null)c.close();}}
}
